class MyApp : Application() {
    override fun onCreate() {
        super.onCreate()
        // App-level initialization
    }
}

android {
    defaultConfig {
        multiDexEnabled true
    }
}

dependencies {
    implementation "androidx.multidex:multidex:2.0.1"
}

// Activity A is at the top of the stack
val intent = Intent(this, ActivityA::class.java)
startActivity(intent) // onNewIntent() is called instead of creating a new instance

override fun onDestroy() {
    super.onDestroy()
    if (isChangingConfigurations) {
        Log.d("ActivityLifecycle", "Destroyed due to configuration change")
    } else {
        Log.d("ActivityLifecycle", "Destroyed permanently")
    }
}

class MyFragment : Fragment() {
    companion object {
        fun newInstance(userId: Int) = MyFragment().apply {
            arguments = Bundle().apply { putInt("userId", userId) }
        }
    }
}
// Access data
val userId = arguments?.getInt("userId")

coroutineScope {
    val a = async { fetchDataA() }
    val b = async { fetchDataB() }
    val results = awaitAll(a, b)
}

