Observable.zip(
    api.getUser().subscribeOn(Schedulers.io()),
    api.getProfile().subscribeOn(Schedulers.io()),
    { user, profile -> Pair(user, profile) }
).observeOn(AndroidSchedulers.mainThread())
 .subscribe { (user, profile) -> /* update UI */ }

RxTextView.textChanges(searchView)
    .debounce(300, TimeUnit.MILLISECONDS)
    .distinctUntilChanged()
    .filter { it.length >= 3 }
    .switchMap { query -> api.search(query).subscribeOn(Schedulers.io()) }
    .observeOn(AndroidSchedulers.mainThread())
    .subscribe { results -> updateUI(results) }

@Volatile private var instance: MySingleton? = null
fun getInstance() = instance ?: synchronized(this) {
    instance ?: MySingleton().also { instance = it }
}

task copyApk(type: Copy) {
    from "build/outputs/apk/release/"
    into "../distribution/"
    include "*.apk"
}

// Or a simple task:
task hello {
    doLast {
        println 'Hello from custom task!'
    }
}

